// CPV codes voor IT/security/compliance
const CPV_CODES = [
  '72000000','72200000','72210000','72220000','72221000',
  '72222000','72222100','72222300','72224000','72300000',
  '72500000','72600000','72700000','79400000','79410000',
  '79411000','48000000','48600000'
];

// Keywords regex
const KEYWORDS = /CRA|AIACT|NIS2|DORA|BIO|AVG|GDPR|NEN.?7510|informatiebeveiliging|cybersecurity|compliance|risicoanalyse|audit|pentest|advies|implementatie|interim|cloud|SIEM|SOC|assessment|zero.?trust|encryptie/i;

const input = $input.first().json;
const tenders = Array.isArray(input) ? input : (input.resultaten || input.publicaties || input.content || []);

const filtered = tenders.filter(t => {
  const cpvMatch = (t.cpvCodes || []).some(c => CPV_CODES.includes(String(c).substring(0, 8)));
  const text = (t.titel || '') + ' ' + (t.omschrijving || '') + ' ' + (t.aanbestedendeDienst || '');
  const kwMatch = KEYWORDS.test(text);
  return cpvMatch || kwMatch;
});

if (filtered.length === 0) {
  return [];  // stopt de ketting
}

return filtered.map(t => ({
  json: {
    titel: t.titel || 'Onbekend',
    geraamdeWaarde: t.geraamdeWaarde || t.geraamdeBedrag || 'budget onbekend',
    sluitingsDatum: t.sluitingsDatum || t.uitersteInschrijfdatum || 'onbekend',
    publicatieLink: t.publicatieLink || t.url || `https://www.tenderned.nl/aankondigingen/overzicht/` + (t.publicatieId || ''),
    aanbesteder: t.aanbestedendeDienst || '-',
    cpvCodes: (t.cpvCodes || []).join(', ')
  }
}));

// Build Slack message from all filtered tenders
const items = $input.all();
if (items.length === 0) return [];

let msg = `📋 *TenderNed — ${items.length} relevante aanbestedingen*\n\n`;

for (const item of items) {
  const t = item.json;
  msg += `• *${t.titel}*\n`;
  msg += `  💶 ${t.geraamdeWaarde}\n`;
  msg += `  📅 Deadline: ${t.sluitingsDatum}\n`;
  msg += `  🏢 ${t.aanbesteder}\n`;
  msg += `  🔗 ${t.publicatieLink}\n\n`;
}

return [{ json: { text: msg } }];
